import React from 'react';
import styled from '@emotion/styled';
import Layout from 'src/components/GlobalLayout';
import GlobalStyles from 'src/components/GlobalStyles';
import PostCard from 'src/components/PostCard';
import { graphql } from 'gatsby';
import { PostGrid, EmptyState } from 'src/styles/PageStyles';

// ============================================================
// Study Page — 당근(Daangn) 블로그 스타일 재설계
// ============================================================

interface StudyPageProps {
  data: {
    allMarkdownRemark: {
      nodes: Array<{
        id: string;
        frontmatter: {
          title: string;
          date: string;
          category: string;
          thumbnail?: { childImageSharp: { gatsbyImageData: any } };
        };
        excerpt: string;
        fields: { slug: string };
        timeToRead?: number;
      }>;
      totalCount: number;
    };
  };
}

const PageInner = styled.div`
  max-width: 1180px;
  margin: 0 auto;
  padding: 0 var(--space-5) var(--space-24);

  @media (min-width: 640px) {
    padding: 0 var(--space-6) var(--space-24);
  }

  @media (min-width: 1024px) {
    padding: 0 var(--space-8) var(--space-32);
  }
`;

const PageTop = styled.div`
  padding: var(--space-12) 0 var(--space-10);
  border-bottom: 1px solid var(--color-border-subtle);
  margin-bottom: var(--space-10);

  @media (min-width: 768px) {
    padding: var(--space-14) 0 var(--space-12);
  }
`;

const Eyebrow = styled.div`
  display: flex;
  align-items: center;
  gap: var(--space-2);
  margin-bottom: var(--space-4);
`;

const EyebrowIcon = styled.span`
  font-size: 1.25rem;
`;

const EyebrowText = styled.span`
  font-size: var(--fs-xs);
  font-weight: var(--fw-bold);
  color: var(--color-brand-primary);
  letter-spacing: var(--ls-wider);
  text-transform: uppercase;
`;

const PageTitle = styled.h1`
  font-size: 2rem;
  font-weight: var(--fw-black);
  color: var(--color-text-primary);
  margin: 0 0 var(--space-3) 0;
  letter-spacing: -0.04em;
  line-height: 1.2;
  word-break: keep-all;

  @media (min-width: 768px) {
    font-size: 2.75rem;
  }
`;

const PageSubtitle = styled.p`
  font-size: var(--fs-body-md);
  color: var(--color-text-secondary);
  line-height: var(--lh-relaxed);
  margin: 0;
  word-break: keep-all;
`;

const CountBadge = styled.span`
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 24px;
  height: 24px;
  padding: 0 var(--space-2);
  background: var(--color-bg-muted);
  color: var(--color-text-secondary);
  border-radius: var(--radius-full);
  font-size: var(--fs-xs);
  font-weight: var(--fw-semibold);
  vertical-align: middle;
  margin-left: var(--space-2);
`;

const StudyPage: React.FC<StudyPageProps> = ({ data }) => {
  const posts = data.allMarkdownRemark.nodes;
  const totalCount = data.allMarkdownRemark.totalCount;

  return (
    <>
      <GlobalStyles />
      <Layout>
        <PageInner>
          <PageTop>
            <Eyebrow>
              <EyebrowIcon>📚</EyebrowIcon>
              <EyebrowText>Study</EyebrowText>
            </Eyebrow>
            <PageTitle>
              스터디 노트
              {totalCount > 0 && <CountBadge>{totalCount}</CountBadge>}
            </PageTitle>
            <PageSubtitle>
              새로운 기술과 개념을 학습하며 정리한 내용들을 모았습니다
            </PageSubtitle>
          </PageTop>

          {posts.length > 0 ? (
            <PostGrid>
              {posts.map((post) => (
                <PostCard
                  key={post.id}
                  title={post.frontmatter.title}
                  excerpt={post.excerpt}
                  date={post.frontmatter.date}
                  category={post.frontmatter.category}
                  slug={post.fields.slug}
                  readTime={post.timeToRead ? `${post.timeToRead}분` : undefined}
                  thumbnail={post.frontmatter.thumbnail?.childImageSharp?.gatsbyImageData}
                />
              ))}
            </PostGrid>
          ) : (
            <EmptyState>
              <span className="emoji">📚</span>
              <h3>아직 스터디 글이 없어요</h3>
              <p>첫 번째 스터디 노트를 작성해보세요!</p>
            </EmptyState>
          )}
        </PageInner>
      </Layout>
    </>
  );
};

export const query = graphql`
  query {
    allMarkdownRemark(
      filter: { frontmatter: { category: { eq: "study" } } }
      sort: { frontmatter: { date: DESC } }
    ) {
      nodes {
        id
        frontmatter {
          title
          date(formatString: "YYYY년 MM월 DD일")
          category
          thumbnail {
            childImageSharp {
              gatsbyImageData(width: 600, height: 338, placeholder: BLURRED)
            }
          }
        }
        excerpt(pruneLength: 160)
        fields {
          slug
        }
        timeToRead
      }
      totalCount
    }
  }
`;

export const Head = () => (
  <>
    <title>스터디 | Dev.log</title>
    <meta name="description" content="개발 학습 내용을 정리한 스터디 노트" />
  </>
);

export default StudyPage;
